My JAVA implementation: [Updated]
Approach:
Merge: (Let me know if it is not clear)
 At each level we will either merge the intervals from both the interval list (if overlap), or take the one that is starts first
 Compare with the last merged interval, with the current collected list.

```
//     Similar to : https://leetcode.com/problems/interval-list-intersections/
    public int[][] intersectionOfTwoIntervals(int[][] a, int[][] b) {
        List<int[]> result = new ArrayList<>();
        int p1 = 0, p2 = 0, l1 = a.length, l2 = b.length;
        while (p1 < l1 && p2 < l2) {
            int[] v1 = a[p1], v2 = b[p2];
            if (hasOverLap(v1, v2)) {
                result.add(getIntersections(v1, v2));
            }
            if (v1[1] < v2[1]) {
                p1++;
            } else {
                p2++;
            }
        }
        return result.toArray(new int[0][0]);
    }

    private int[] getIntersections(int[] i1, int[] i2) {
        return new int[]{Math.max(i1[0], i2[0]), Math.min(i1[0], i2[1])};
    }

    public List<int[]> mergeTwoIntervals(int[][] i1, int[][] i2) {
        Stack<int[]> merged = new Stack<>();
        int p1 = 0, p2 = 0, l1 = a.length, l2 = b.length;
        while (p1 < l1 && p2 < l2) {
            int[] v1 = a[p1], v2 = b[p2], cur = new int[2];
            if (hasOverLap(v1, v2)) {
                cur = getMerged(v1, v2);
            }
//            Check if the current interval has overlap with the previously inserted interval
            if (hasOverLap(merged.peek(), cur)) merged.add(getMerged(merged.pop(), cur));
            else merged.add(cur);
            if (v1[1] < v2[1]) p1++;
            else p2++;
        }
        while (p1 < l1) {
            int[] cur = a[p1++];
            if (hasOverLap(merged.peek(), cur)) merged.add(getMerged(merged.pop(), cur));
            else merged.add(cur);
        }
        while (p2 < l2) {
            int[] cur = a[p2++];
            if (hasOverLap(merged.peek(), cur)) merged.add(getMerged(merged.pop(), cur));
            else merged.add(cur);
        }
        LinkedList<int[]> result = new LinkedList<>();
        while (!merged.isEmpty()) {
            result.addFirst(merged.pop());
        }
        return result;
    }

    private int[] getMerged(int[] p1, int[] p2) {
        return new int[]{Math.min(p1[0], p2[0]), Math.max(p1[1], p2[1])};
    }

    private boolean hasOverLap(int[] i1, int[] i2) {
        if (i1[0] > i2[0]) return hasOverLap(i2, i1);
//       Assuming i1 interval starts first.
        return Math.max(i1[0], i2[0]) <= Math.min(i1[1], i2[1]);
    }
```

Python solution
```
def orTwoSortedLists(listA, listB):
    res = [] # Except ouput Space O(1)
    while len(listA) and len(listB): # Time O(N)
        firstA = listA[0]
        firstB = listB[0]        
        if firstA <= firstB:
            res.append(listA.pop(0))
            if firstA == firstB:
                # Don't need to keep redundant one and thus remove it
                listB.pop(0)
        else:
            res.append(listB.pop(0))

    def handleLeftOvers(res, listX):
        while len(listX):
            last = res[-1]
            first = listX.pop(0)
            if last != first:
                res.append(first)

    if len(res) == 0:
        res += listA
    else:
        handleLeftOvers(res, listA) # Time O(N)
    if len(res) == 0:
        res += listB
    else:
        handleLeftOvers(res, listB) # Time O(N)
    return res

def andTwoSortedLists(listA, listB):
    indexA = indexB = 0
    lengthA = len(listA)
    lengthB = len(listB)
    res = [] # Except output Space O(1)
    while indexA < lengthA and indexB < lengthB: # Time O(N)
        if listA[indexA] == listB[indexB]:
            res.append(listA[indexA])
            indexA += 1
            indexB += 1
        elif listA[indexA] < listB[indexB]:
            indexA += 1
        else:
            indexB += 1
    return res

print(orTwoSortedLists([1, 4, 7, 12], [2, 4, 6, 10, 12]))
print(orTwoSortedLists([], [1, 2, 3]))
print(andTwoSortedLists([1, 4, 7, 12], [2, 4, 6, 10, 12]))
print(andTwoSortedLists([], [1, 2, 3]))
